def insert_line(node, new):
    l, r = node.l, node.r
    mid = (l + r) // 2
    if node.line is None:
        node.line = new
        return
    left_better = new.eval(l) > node.line.eval(l)
    mid_better = new.eval(mid) > node.line.eval(mid)
    right_better = new.eval(r) > node.line.eval(r)
    if mid_better:
        node.line, new = new, node.line
    if l == r:
        return
    if left_better != mid_better:
        if node.left is None:
            node.left = Node(l, mid)
        insert_line(node.left, new)
    if right_better != mid_better:
        if node.right is None:
            node.right = Node(mid + 1, r)
        insert_line(node.right, new)

